            //
            aOrbiterK = (aOrbiterK + aOrbiterG) + 0xB9750FAEBEEABA97ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterK) ^ 0x83CA90233F6581CEULL;
            aOrbiterH = RotL64((aOrbiterH * 0xF6704AD97270EE5DULL), 3U);
