            aOrbiterJ = (aOrbiterJ + aOrbiterG) + 0x2C897D5239BF0565ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterJ) ^ 0x483454BCE7DCFD48ULL) ^ aPhaseDOrbiterUpdateSaltC[((aIndex + 4U)) & S_SALT1];
