            aOrbiterD = (aWandererF + RotL64(aPrevious, 57U)) + 0x9CA6202E73661371ULL;
            aOrbiterA = (aWandererJ + RotL64(aScatter, 6U)) + 0x48965A5EA8843ACEULL;
            aOrbiterB = (((aWandererD + RotL64(aCross, 51U)) + RotL64(aCarry, 53U)) + 0x9F37A98A6DCF694DULL) + aPhaseHOrbiterAssignSaltB[((aIndex + 28U)) & S_SALT1];
            aOrbiterC = ((aWandererA + RotL64(aScatter, 29U)) + RotL64(aCarry, 29U)) + 0xC24C098E037F29A1ULL;
