            aOrbiterJ = (aWandererB + RotL64(aPrevious, 10U)) + 0x80AE0B379DB024CEULL;
            aOrbiterF = ((aWandererG + RotL64(aCross, 21U)) + 0xB46E74611BCB3583ULL) + aPhaseHOrbiterAssignSaltF[((aIndex + 15U)) & S_SALT1];
            //
            aOrbiterK = (aOrbiterK + aOrbiterG) + 0x13BBD334F8DE1B42ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterK) ^ 0x2E970853B681AD24ULL;
            aOrbiterD = RotL64((aOrbiterD * 0x23A0CA57B0BE0673ULL), 47U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterA) + 0xEB0987E911C5910EULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterG) ^ 0x5282EE8D9CB84211ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x01DC1F324078F871ULL), 57U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterB) + 0x2FAFED5DAC231CD4ULL;
            aOrbiterC = ((aOrbiterC ^ aOrbiterD) ^ 0x05689F8854524C13ULL) ^ aPhaseHOrbiterUpdateSaltC[(((31U - aIndex) + 8U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 0xDEE08A9052502CADULL), 11U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterI) + 0x0B35A0CF6D27327EULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterC) ^ 0x2B3D0AF2CCE05482ULL;
            aOrbiterA = RotL64((aOrbiterA * 0x9F08146A5D0FC1F9ULL), 35U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterD) + 0xD3416384796E68A1ULL) + aPhaseHOrbiterUpdateSaltD[((aIndex + 6U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 0x74E3FB649EB20271ULL;
            aOrbiterF = RotL64((aOrbiterF * 0xFDE2AA1CDF1A0D19ULL), 19U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterC) + 0x614A37673A12A850ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterF) ^ 0xFAB21CB524958F68ULL;
            aOrbiterG = RotL64((aOrbiterG * 0x42F62D47CE1B93F1ULL), 43U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterJ) + 0xA8B948D15E0ED972ULL) + aPhaseHOrbiterUpdateSaltB[((aIndex + 13U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterB) ^ 0x41151F0D747E92B7ULL;
