            aWandererF = aWandererF + (((RotL64(aCross, 56U) + aOrbiterG) + RotL64(aOrbiterD, 10U)) + aPhaseHWandererUpdateSaltC[(((31U - aIndex) + 23U)) & S_SALT1]);
            aWandererJ = aWandererJ ^ ((RotL64(aScatter, 51U) + aOrbiterJ) + RotL64(aOrbiterB, 3U));
