            aWandererG = aWandererG + ((RotL64(aIngress, 13U) + aOrbiterI) + RotL64(aOrbiterJ, 14U));
            aWandererB = aWandererB ^ ((RotL64(aPrevious, 5U) + RotL64(aOrbiterA, 39U)) + aOrbiterJ);
            aWandererA = aWandererA + ((RotL64(aIngress, 60U) + aOrbiterG) + RotL64(aOrbiterC, 57U));
            //
            aCarry = aCarry + (RotL64(aWandererE, 44U) ^ aWandererF);
            aCarry = aCarry + (RotL64(aWandererB, 47U) ^ aWandererJ);
            aCarry = aCarry + (RotL64(aWandererC, 21U) ^ aWandererA);
            aCarry = aCarry + (aWandererD ^ RotL64(aWandererG, 41U));
            aCarry = aCarry + RotL64(aWandererI, 51U);
            aCarry = aCarry + RotL64(aIngress, 5U);
