            aOrbiterK = (aWandererC + RotL64(aPrevious, 27U)) + 0x29D750974E248930ULL;
            aOrbiterC = (aWandererH + RotL64(aIngress, 47U)) + 0xB465856B92276163ULL;
            aOrbiterG = (aWandererA + RotL64(aCross, 43U)) + 0xE35A367D7DF7DBAFULL;
            aOrbiterJ = ((aWandererF + RotL64(aScatter, 38U)) + RotL64(aCarry, 37U)) + 0x23CAF03D8E276202ULL;
            aOrbiterE = (aWandererG + RotL64(aCross, 3U)) + 0xD5EC7A977BDCBC95ULL;
            //
            aOrbiterB = ((aOrbiterB + aOrbiterI) + 0x1779B9DAE15EE161ULL) + aPhaseHOrbiterUpdateSaltC[(((31U - aIndex) + 15U)) & S_SALT1];
            aOrbiterF = ((aOrbiterF ^ aOrbiterB) ^ 0x651BBADD2B922101ULL) ^ aPhaseHOrbiterUpdateSaltE[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0x332E49EDC3C6209FULL), 11U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 0x37F31A241DAA4A07ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterA) ^ 0x6C6FD67C122D2D93ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x0F417BC3AFBCF2E9ULL), 47U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterK) + 0x67DCE958E23048C5ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterC) ^ 0xCCA08DB5A9FB9376ULL;
            aOrbiterG = RotL64((aOrbiterG * 0x119B93685D1188FBULL), 23U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterJ) + 0x2EE12C75BCC7D48AULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterK) ^ 0xD2085F88B55AB81DULL;
            aOrbiterB = RotL64((aOrbiterB * 0xBB9F9E71EF5DB1CFULL), 43U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterA) + 0x1431683CF7D5017FULL) + aPhaseHOrbiterUpdateSaltA[((aIndex + 6U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterE) ^ 0x19709389E2CFA51EULL;
            aOrbiterC = RotL64((aOrbiterC * 0x587E505B0F88E41FULL), 51U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterG) + 0xD92AE584C4EF71B6ULL) + aPhaseHOrbiterUpdateSaltB[((aIndex + 18U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterI) ^ 0xABE68F59506FD526ULL;
            aOrbiterE = RotL64((aOrbiterE * 0x864E367371C0C85FULL), 35U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 0x6B6AC9269F8D64EDULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterJ) ^ 0x273F2A39B1018C0DULL;
            aOrbiterI = RotL64((aOrbiterI * 0x61A84EDB773309EBULL), 19U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 0xFE0E3FADA17B7AAEULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterG) ^ 0x0A4509E45884546AULL;
            aOrbiterA = RotL64((aOrbiterA * 0x6BEE868427151F85ULL), 3U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterE) + 0xD97DA63252962EF5ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterF) ^ 0x7554F4267F353FBDULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xD8F48651EE04225DULL), 29U);
            //
            aIngress = RotL64(aOrbiterA, 50U) ^ aOrbiterF;
            aIngress = aIngress + (aOrbiterI ^ RotL64(aOrbiterG, 47U));
            aIngress = aIngress + (aOrbiterB ^ RotL64(aOrbiterE, 11U));
            aIngress = aIngress + (RotL64(aOrbiterK, 53U) ^ aOrbiterJ);
            aIngress = aIngress + RotL64(aOrbiterC, 34U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererA = aWandererA ^ ((RotL64(aScatter, 60U) + aOrbiterI) + RotL64(aOrbiterB, 46U));
            aWandererC = aWandererC + (((RotL64(aIngress, 53U) + aOrbiterK) + RotL64(aOrbiterB, 57U)) + RotL64(aCarry, 19U));
            aWandererF = aWandererF ^ ((RotL64(aPrevious, 43U) + RotL64(aOrbiterJ, 21U)) + aOrbiterA);
            aWandererK = aWandererK + (((RotL64(aCross, 13U) + RotL64(aOrbiterE, 13U)) + aOrbiterA) + aPhaseHWandererUpdateSaltF[((aIndex + 23U)) & S_SALT1]);
            aWandererB = aWandererB ^ ((RotL64(aIngress, 47U) + RotL64(aOrbiterF, 41U)) + aOrbiterC);
